                // ZDAJ PRIDE POSEBNA LOGIKA - 1. POGLEDAMO ALI LAHKO SWAPAMO REST DAY
                val canSwap = checkIfFutureRestDaysExistAndSwap(yesterdayStr)

                if (canSwap) {
                    // Swap uspešen, včeraj smo spremenili v REST day automatsko, streak ne pade.
                    userRef.collection("daily_logs").document(yesterdayStr).set(mapOf(
                        "date" to yesterdayStr,
                        "status" to "REST_SWAPPED",
                        "timestamp" to Clock.System.now().toEpochMilliseconds()
                    )).await()
                    Log.d("GamificationRepo", "Workout zgrešen, a je bil nadomeščen s Swap-om Rest dneva.")
                    return
                }

                // NI VEČ REST DAYEV V TEDNU. 2. POGLEDAMO ČE IMAMO STREAK FREEZE.
                val freezeUsed = consumeStreakFreeze()
                if (freezeUsed) {
                    // Uspešno uporabljen STREAK FREEZE.
                    userRef.collection("daily_logs").document(yesterdayStr).set(mapOf(
                        "date" to yesterdayStr,
                        "status" to "FROZEN",
                        "timestamp" to Clock.System.now().toEpochMilliseconds()
                    )).await()
                    Log.d("GamificationRepo", "Streak Freeze uspešno porabljen. Streak ohranjen.")
                } else {
                    // NO FREEZE. STREAK PADE NA 0.
                    userRef.update("streak_days", 0).await()
                    Log.d("GamificationRepo", "Ni rest dnevov in ni freeze-a. Streak je padel na 0.")
                }
            }
        } catch (e: Exception) {
            Log.e("GamificationRepo", "Midnight streak check failed.", e)
        }
    }

    private suspend fun checkIfFutureRestDaysExistAndSwap(missedDateStr: String): Boolean {
        Log.d("GamificationRepo", "Checking if we can auto-swap missed workout ($missedDateStr) for a future REST day in current week")
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return false
        try {
            // 1. Dobimo plan dokument
            val docRef = db.collection("user_plans").document(userRef.id)
            val snapshot = docRef.get().await()
            if (!snapshot.exists()) return false

            @Suppress("UNCHECKED_CAST")
            val plansList = snapshot.get("plans") as? MutableList<Map<String, Any>> ?: return false
            if (plansList.isEmpty()) return false
            val currentPlan = plansList.first().toMutableMap()

            // 2. Najdemo kateri dan v planu smo (preštejemo dni zabeležene v daily_logs)
            val logsSnap = userRef.collection("daily_logs").get().await()
            val currentPlanDayNum = logsSnap.documents.size + 1

            @Suppress("UNCHECKED_CAST")
            val weeksList = currentPlan["weeks"] as? MutableList<Map<String, Any>> ?: return false

            var foundRestDay = false
            var targetRestWeekIndex = -1
            var targetRestDayIndex = -1
            var missedWeekIndex = -1
            var missedDayIndex = -1

            // Iskanje včerajšnjega dneva
            for ((wIndex, week) in weeksList.withIndex()) {
                @Suppress("UNCHECKED_CAST")
                val days = week["days"] as? MutableList<Map<String, Any>> ?: continue
                for ((dIndex, day) in days.withIndex()) {
                    val dayNum = (day["dayNumber"] as? Number)?.toInt() ?: 0
                    if (dayNum == currentPlanDayNum) {
                         missedWeekIndex = wIndex
                         missedDayIndex = dIndex
                    }
                    if (missedWeekIndex != -1 && dayNum > currentPlanDayNum) {
                        val isRest = day["isRestDay"] as? Boolean ?: false
                        if (isRest && !foundRestDay) {
                           targetRestWeekIndex = wIndex
                           targetRestDayIndex = dIndex
                           foundRestDay = true
                        }
                    }
                }
            }

            if (!foundRestDay || missedWeekIndex == -1) return false

            // Perform SWAP
            @Suppress("UNCHECKED_CAST")
            val missedWeek = (weeksList[missedWeekIndex] as Map<String, Any>).toMutableMap()
            @Suppress("UNCHECKED_CAST")
            val missedDays = (missedWeek["days"] as List<Map<String, Any>>).map { it.toMutableMap() }.toMutableList()

            @Suppress("UNCHECKED_CAST")
            val targetWeek = if (missedWeekIndex == targetRestWeekIndex) missedWeek else (weeksList[targetRestWeekIndex] as Map<String, Any>).toMutableMap()
            @Suppress("UNCHECKED_CAST")
            val targetDays = if (missedWeekIndex == targetRestWeekIndex) missedDays else (targetWeek["days"] as List<Map<String, Any>>).map { it.toMutableMap() }.toMutableList()

            // missedDay postane Rest
            missedDays[missedDayIndex]["isRestDay"] = true
            missedDays[missedDayIndex]["isSwapped"] = true

            // future day postane Workout (podeduje focus)
            val originalFocus = missedDays[missedDayIndex]["focusLabel"] ?: ""
            targetDays[targetRestDayIndex]["isRestDay"] = false
            targetDays[targetRestDayIndex]["focusLabel"] = originalFocus
            targetDays[targetRestDayIndex]["isSwapped"] = true

            missedWeek["days"] = missedDays
            weeksList[missedWeekIndex] = missedWeek

            if (missedWeekIndex != targetRestWeekIndex) {
                 targetWeek["days"] = targetDays
                 weeksList[targetRestWeekIndex] = targetWeek
            }

            currentPlan["weeks"] = weeksList
            plansList[0] = currentPlan

            docRef.update("plans", plansList).await()
            return true

        } catch (e: Exception) {
            Log.e("GamificationRepo", "Swap algorithem padel", e)
            return false
        }
    }
}

package com.example.myapplication.data.settings

import android.content.Context
import android.util.Log
import com.example.myapplication.domain.settings.SettingsManager
import com.example.myapplication.domain.settings.SettingsProvider
import com.russhwolf.settings.Settings
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flowOf
import kotlinx.datetime.Clock
import kotlinx.datetime.TimeZone
import kotlinx.datetime.toLocalDateTime

/**
 * TODO: Migration to pure KMP. This is currently tightly coupled with Context.
 */
class UserPreferencesRepository(private val context: Context) {

    // Using Multiplatform Settings instead of SharedPreferences directly
    private val settings: Settings = com.russhwolf.settings.SharedPreferencesSettings(context.getSharedPreferences("user_prefs", Context.MODE_PRIVATE))
    private val bmSettings: Settings = com.russhwolf.settings.SharedPreferencesSettings(context.getSharedPreferences("bm_prefs", Context.MODE_PRIVATE))

    // Obstojeći SharedPrefs prenašamo v Settings objekt, ampak trenutno še vedno podpiramo star behavior do popolne menjave

    fun getUserDataChanges(): Flow<com.example.myapplication.data.UserProfile?> {
        return flowOf(null) // Mocked for now - wait for serialization setup or use custom string mapping
    }

    fun getUserId(): String? {
        return settings.getStringOrNull("user_id")
    }

    fun setUserId(userId: String?) {
        if (userId == null) settings.remove("user_id") else settings.putString("user_id", userId)
    }

    fun getUserToken(): String? {
        return settings.getStringOrNull("user_token")
    }

    fun getWeeklyTargetFlow(): Flow<Int> {
        return flowOf(bmSettings.getInt("weekly_target", 0))
    }

    fun getLastWorkoutEpochFlow(): Flow<Long> {
        return flowOf(bmSettings.getLong("last_workout_epoch", 0L))
    }

    fun isWorkoutDoneToday(): Boolean {
        val lastEpoch = bmSettings.getLong("last_workout_epoch", 0L)
        return if (lastEpoch == 0L) false
        else {
            val now = Clock.System.now().toLocalDateTime(TimeZone.currentSystemDefault()).date
            val lastDate = kotlinx.datetime.LocalDate.fromEpochDays(lastEpoch.toInt())
            lastDate == now
        }
    }

    fun getPlanDay(): Int {
        return bmSettings.getInt("plan_day", 1)
    }

    fun getWeeklyTarget(): Int {
        return bmSettings.getInt("weekly_target", 3)
    }

    fun setUserToken(token: String?) {
        if (token == null) settings.remove("user_token") else settings.putString("user_token", token)
    }

    fun isDarkModeEnabled(): Boolean {
        return settings.getBoolean("dark_mode", true)
    }

    fun setDarkModeEnabled(enabled: Boolean) {
        settings.putBoolean("dark_mode", enabled)
    }

    fun isFreshStartOnLogin(): Boolean {
        return settings.getBoolean("fresh_start_on_login", false)
    }

    fun setFreshStartOnLogin(freshStart: Boolean) {
        settings.putBoolean("fresh_start_on_login", freshStart)
    }

    /**
     * ⚠️ DELNO DEPRECATED (Faza 9.2): Ta funkcija piše v bm_prefs kot lokalni fallback cache.
     * Resnični SSOT je Firestore prek UserProfileManager.saveWorkoutStats().
     * Ostane funkcionalna samo za offline fallback v GetBodyMetricsUseCase.getPlanDay().
     * TODO (Faza 10): Odstrani bm_prefs zapis ko GetBodyMetricsUseCase ne bo več potreboval localnega fallbacka.
     */
    suspend fun updateWorkoutStats(completedDay: Int, timestamp: Long) {
        bmSettings.putInt("plan_day", completedDay)
        val epochDay = timestamp / (1000 * 60 * 60 * 24)
        bmSettings.putLong("last_workout_epoch", epochDay)
    }

    /**
     * ⚠️ NO-OP — DEPRECATED (Faza 9.1+9.2): Kalorije se zapisujejo prek DailyLogRepository.updateDailyLog().
     * bm_prefs.daily_calories ni več SSOT. Klic je bil odstranjen iz UpdateBodyMetricsUseCase v Fazi 9.1.
     */
    suspend fun updateDailyCalories(calories: Double, timestamp: Long) {
        // NO-OP: SSOT je DailyLogRepository. Bm_prefs zapis je bil ukinjen v Fazi 9.1.
    }

    fun getDailyCalories(): Double {
        val lastSavedEpochDay = bmSettings.getLong("daily_calories_epoch", 0L)
        val todayEpochDay = System.currentTimeMillis() / (1000 * 60 * 60 * 24)
        return if (todayEpochDay == lastSavedEpochDay) {
            bmSettings.getFloat("daily_calories", 0f).toDouble()
        } else {
            0.0
        }
    }

    fun getDailyCaloriesFlow(): Flow<Double> {
        return kotlinx.coroutines.flow.flow {
            val lastSavedEpochDay = bmSettings.getLong("daily_calories_epoch", 0L)
            val todayEpochDay = System.currentTimeMillis() / (1000 * 60 * 60 * 24)
            if (todayEpochDay == lastSavedEpochDay) {
                emit(bmSettings.getFloat("daily_calories", 0f).toDouble())
            } else {
                emit(0.0)
            }
        }
    }

    fun clearAllSettings() {
        settings.clear()
        setFreshStartOnLogin(true)
    }
}

