completed"), 0), totalCaloriesBurned = s.getFloat(userKey(email, KEY_TOTAL_CALORIES), 0f).toDouble(), earlyBirdWorkouts = s.getInt(userKey(email, KEY_EARLY_BIRD), 0), nightOwlWorkouts = s.getInt(userKey(email, KEY_NIGHT_OWL), 0), currentLoginStreak = s.getInt(userKey(email, "streak_days"), 0), lastLoginDate = s.getStringOrNull(userKey(email, KEY_LAST_LOGIN)), totalPlansCreated = s.getInt(userKey(email, KEY_TOTAL_PLANS), 0), profilePictureUrl = s.getStringOrNull(userKey(email, KEY_PROFILE_PICTURE)), height = if (heightVal > 0) heightVal else null, age = if (ageVal > 0) ageVal else null, gender = s.getStringOrNull(userKey(email, "gender")), activityLevel = s.getStringOrNull(userKey(email, "activityLevel")), experience = s.getStringOrNull(userKey(email, "experience")), bodyFat = s.getStringOrNull(userKey(email, "bodyFat")), workoutGoal = s.getString(userKey(email, "workoutGoal"), ""), limitations = s.getString(userKey(email, "limitations"), "").split(",").filter { it.isNotBlank() }, nutritionStyle = s.getStringOrNull(userKey(email, "nutritionStyle")), sleepHours = s.getStringOrNull(userKey(email, "sleepHours")), focusAreas = s.getString(userKey(email, "focusAreas"), "").split(",").filter { it.isNotBlank() } ) }
