import androidx.compose.ui.unit.sp
import kotlinx.coroutines.delay

@Composable
fun XPPopup(
    xpAmount: Int,
    isVisible: Boolean,
    onDismiss: () -> Unit
) {
    if (!isVisible) return

    var shouldFadeOut by remember { mutableStateOf(false) }

    LaunchedEffect(isVisible) {
        if (isVisible) {
            delay(2500) // Prikaži pop-up 2.5 sekunde
            shouldFadeOut = true
            delay(300) // Čakaj za animacijo
            onDismiss()
        }
    }

    val alpha by animateFloatAsState(if (shouldFadeOut) 0f else 1f)

    Box(
        modifier = Modifier
            .fillMaxWidth()
            .padding(16.dp)
            .alpha(alpha),
        contentAlignment = Alignment.TopCenter
    ) {
        Box(
            modifier = Modifier
                .clip(RoundedCornerShape(12.dp))
                .background(MaterialTheme.colorScheme.primary)
                .padding(horizontal = 20.dp, vertical = 12.dp),
            contentAlignment = Alignment.Center
        ) {
            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.Center,
                modifier = Modifier.fillMaxWidth()
            ) {
                Text(
                    text = "✨ +$xpAmount XP",
                    fontSize = 18.sp,
                    fontWeight = FontWeight.Bold,
                    // onPrimary zagotovi kontrast v obeh temah:
                    // Light: kremasto bela (#FCFBF8) na temno vijolični → ✅
                    // Dark:  temno vijolična (#38305A) na svetli pastelni → ✅
                    color = MaterialTheme.colorScheme.onPrimary
                )
            }
        }
    }
}

@file:OptIn(androidx.compose.material3.ExperimentalMaterial3Api::class)

package com.example.myapplication.ui.screens

import kotlinx.datetime.toLocalDateTime

// =====================================================================
// NutritionScreen.kt
// Vsebuje: glavni NutritionScreen composable, ActiveCaloriesBar,
//          NutritionDetailRow.
// Modeli/enumi    â†’ NutritionModels.kt
// Custom View     â†’ DonutProgressView.kt
// Dialogi         â†’ NutritionDialogs.kt
// Iskanje hrane   â†’ AddFoodSheet.kt
// =====================================================================

import android.content.Context
import android.util.Log
import com.example.myapplication.data.PlanResult
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.rememberScrollState
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.foundation.verticalScroll
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clip
import androidx.compose.ui.graphics.Brush
import androidx.compose.ui.graphics.Color
import androidx.compose.material3.MaterialTheme
import androidx.compose.ui.graphics.toArgb
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.res.painterResource
import androidx.compose.ui.input.nestedscroll.nestedScroll
import androidx.compose.ui.text.font.FontWeight
